#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int arr[101]; // N <= 100
        int freq[11] = {0};
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
            if (arr[i] >= 1 && arr[i] <= 10) freq[arr[i]]++;
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", freq[arr[i]]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

