import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        freq = [0] * 11
        for v in arr:
            if 1 <= v <= 10:
                freq[v] += 1
        out_lines.append(' '.join(str(freq[v]) for v in arr))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

