const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const arr = [];
  const freq = new Array(11).fill(0);
  for (let i = 0; i < N; i++) {
    const val = Number(input[idx++]);
    arr.push(val);
    if (val >= 1 && val <= 10) freq[val]++;
  }
  results.push(arr.map(v => freq[v]).join(' '));
}
